import { useEffect, useState } from 'react';
import Home from './components/Routes/Home';
import { useLocation, useOutlet } from 'react-router-dom';
import Navbar from './components/Routes/Navbar';
import Footer from './components/Routes/Footer';
import SweetAlert from './components/Tools/SweetAlert';

function App() {
  const location = useLocation();
  const outlet = useOutlet();
  const [backgroundOutlet, setBackgroundOutlet] = useState(null);

  const isAuthState = location.pathname === '/login' || location.pathname === '/regist';

  useEffect(() => {
    if (!isAuthState) {
      setBackgroundOutlet(outlet);
      document.body.style.overflow = '';
    }
    // //console.log('當前路徑：', location.pathname);
  }, [isAuthState, outlet]);

  // 如果是登入或註冊頁面，則顯示背景內容；否則顯示正常內容
  const pageContent = isAuthState ? (backgroundOutlet ?? <Home />) : outlet;

  return (
    <>
      <Navbar />
      {pageContent}
      <Footer />
      {isAuthState && outlet}
      <SweetAlert />
    </>
  );
}

export default App;

import { createSlice } from '@reduxjs/toolkit';
import { loginThunk, registerThunk, checkThunk, logoutThunk } from './authThunks';

const initialState = {
  status: 'idle', // idle / checking / auth / guest
  user: null,
  token: null,
  error: null,
};

const authSlice = createSlice({
  name: 'auth',
  initialState,
  reducers: {
    clearAuthError: (state) => {
      state.error = null;
    },
  },
  extraReducers: (builder) => {
    builder
      // 一開始check
      .addCase(checkThunk.pending, (state) => {
        state.status = 'checking';
        state.error = null;
      })
      .addCase(checkThunk.fulfilled, (state, action) => {
        const { token, user } = action.payload || {};
        if (token) {
          state.status = 'authed';
          state.token = token;
          state.user = user || null;
        } else {
          state.status = 'guest';
          state.token = null;
          state.user = null;
        }
      })
      .addCase(checkThunk.rejected, (state, action) => {
        state.status = 'guest';
        state.token = null;
        state.user = null;
        state.error = action.payload || '驗證失敗';
      })

      // 登入
      .addCase(loginThunk.pending, (state) => {
        state.error = null;
      })
      .addCase(loginThunk.fulfilled, (state, action) => {
        state.status = 'authed';
        state.token = action.payload.token;
        state.user = action.payload.user || null;
        state.error = null;
      })
      .addCase(loginThunk.rejected, (state, action) => {
        state.status = 'guest';
        state.token = null;
        state.user = null;
        state.error = action.payload || '登入失敗';
      })

      // 註冊
      .addCase(registerThunk.pending, (state) => {
        state.error = null;
      })
      .addCase(registerThunk.fulfilled, (state, action) => {
        if (action.payload?.token) {
          state.status = 'authed';
          state.token = action.payload.token;
          state.user = action.payload.user || null;
        } else {
          state.status = 'guest';
        }
      })
      .addCase(registerThunk.rejected, (state, action) => {
        state.error = action.payload || '註冊失敗';
      })

      // 登出
      .addCase(logoutThunk.fulfilled, (state) => {
        state.status = 'guest';
        state.token = null;
        state.user = null;
        state.error = null;
      });
  },
});

export const { clearAuthError } = authSlice.actions;
export const AuthCheck = (state) => state.auth;
export const AuthStatus = (state) => state.auth.status;
export const authUser = (state) => state.auth.user;
export const authToken = (state) => state.auth.token;

export const IsAuthed = (state) => !!state.auth.token;
export const IsChecking = (state) => state.auth.status === 'checking';

export default authSlice.reducer;

import { createAsyncThunk } from '@reduxjs/toolkit';
import { authStorage } from './authStorage';
import { loginAPI, registAPI, checkAPI } from './authAPI';
import { createWatchlistAPI } from '../wishlist/wishlistAPI';
import { loadingStarted, loadingStopped } from '../loading/loadingSlice';
import { pushMessage } from '../message/messageSlice';

function authResponse(payload) {
  // payload may be wrapped as { success, message, data: { accessToken, user } }
  const data = payload?.data ?? payload ?? {};
  const token = data?.accessToken || null;
  const user = data?.user || null;

  if (!token) {
    throw new Error(payload?.message || 'API failed');
  }

  return { token, user };
}

export const loginThunk = createAsyncThunk(
  'auth/login',
  async (formData, { dispatch, rejectWithValue }) => {
    dispatch(loadingStarted());
    try {
      const payload = await loginAPI(formData);
      // //console.log('[loginThunk] payload:', payload);
      const { token, user } = authResponse(payload);
      // //console.log('[loginThunk] token:', token);

      authStorage.setToken(token);

      dispatch(
        pushMessage({
          type: 'success',
          title: '登入成功',
          timer: 3000,
          backdrop: `rgba(0,0,123,0.4) no-repeat`,
        })
      );
      return { token, user };
    } catch (err) {
      console.error('[loginThunk] error:', err);
      console.error('[loginThunk] err.response:', err?.response?.data);
      return rejectWithValue(err?.message || 'login failed');
    } finally {
      dispatch(loadingStopped());
    }
  }
);

export const registerThunk = createAsyncThunk(
  'auth/register',
  async (formData, { dispatch, rejectWithValue }) => {
    dispatch(loadingStarted());
    try {
      const payload = await registAPI(formData);

      // json-server-auth 回傳新使用者的 accessToken，解出 userId 建立預設 watchlist
      const newUserId = payload?.data?.user?.id ?? payload?.user?.id ?? null;
      if (newUserId) {
        try {
          await createWatchlistAPI(newUserId);
        } catch (_) {
          /* 非致命，忽略 */
        }
      }

      dispatch(pushMessage({ type: 'success', title: '註冊成功，請登入' }));
      return { token: null, user: null };
    } catch (err) {
      dispatch(pushMessage({ type: 'error', title: '註冊失敗' }));
      return rejectWithValue(err?.message || 'register failed');
    } finally {
      dispatch(loadingStopped());
    }
  }
);

export const checkThunk = createAsyncThunk(
  'auth/check',
  async (_, { dispatch, rejectWithValue }) => {
    dispatch(loadingStarted());
    try {
      const token = authStorage.getToken();
      if (!token) return { token: null, user: null };

      const payload = await checkAPI();

      if (payload?.success === false) throw new Error(payload?.message || 'check failed');

      const user = payload?.data?.user ?? payload?.user ?? null;
      return { token, user };
    } catch (err) {
      const status = err?.response?.status;
      const isUnauthorized = status === 401 || status === 403;

      if (isUnauthorized) {
        // 只有 token 明確失效才清
        authStorage.clearToken();
        return rejectWithValue('unauthorized');
      }
      return rejectWithValue('temporary_check_error');
    } finally {
      dispatch(loadingStopped());
    }
  }
);

export const logoutThunk = createAsyncThunk('auth/logout', async (_, { dispatch }) => {
  dispatch(loadingStarted());
  try {
    authStorage.clearToken();
    dispatch(pushMessage({ type: 'info', title: '已登出' }));
    return true;
  } finally {
    dispatch(loadingStopped());
  }
});

