        <div
          style={{
            position: 'fixed',
            inset: 0,
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            backgroundColor: '#0a0a14',
            zIndex: 5000,
          }}
        >
          <BeatLoader color={primaryColor} size={20} />
        </div>
      )}
    </>
  );
}

