import { useEffect, useState, useMemo } from 'react';
import { useSelector } from 'react-redux';
import { authUser } from '../../app/features/auth/authSlice';
import { useWishlist } from '../../contexts/WishlistContext';

// dnd-kit
import { DndContext, closestCenter, PointerSensor, useSensor, useSensors } from '@dnd-kit/core';
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  horizontalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

import { BeatLoader } from 'react-spinners';
import { Heart, Plus, Pencil, Trash2, Check, X, BookmarkCheck, GripVertical } from 'lucide-react';

// ══════════════════════════════════════════════════════════════════
// 可拖曳股票行
// ══════════════════════════════════════════════════════════════════
function SortableStockRow({ symbol, groups, activeGroupId, onRemoveFromGroup, onToggle }) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: symbol,
  });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
    cursor: isDragging ? 'grabbing' : 'default',
  };

  const isInGroup =
    activeGroupId &&
    groups.some((g) => g.id === activeGroupId && g.stockIds.includes(String(symbol)));

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="d-flex align-items-center justify-content-between py-12 px-16 border-bottom bg-white"
    >
      {/* 拖曳把手 */}
      <div className="d-flex align-items-center gap-12">
        <span
          {...attributes}
          {...listeners}
          className="text-muted"
          style={{ cursor: 'grab', touchAction: 'none' }}
          title="拖曳排序"
        >
          <GripVertical size={16} />
        </span>

        <span className="fw-bold">{symbol}</span>

        {/* 群組 badges */}
        {groups
          .filter((g) => g.stockIds.includes(String(symbol)))
          .map((g) => (
            <span key={g.id} className="badge bg-primary-subtle text-primary rounded-pill">
              {g.name}
            </span>
          ))}
      </div>

      <div className="d-flex gap-8">
        {/* 加入 / 移出目前群組 */}
        {activeGroupId && (
          <button
            className={`btn btn-sm ${isInGroup ? 'btn-outline-danger' : 'btn-outline-primary'}`}
            title={isInGroup ? '移出群組' : '加入群組'}
            onClick={() => onRemoveFromGroup(activeGroupId, symbol, isInGroup)}
          >
            {isInGroup ? <X size={14} /> : <Plus size={14} />}
          </button>
        )}
        {/* 取消收藏 */}
        <button
          className="btn btn-sm btn-outline-primary"
          title="取消收藏"
          onClick={() => onToggle(symbol)}
        >
          <Heart size={14} fill="#2fa58d" color="#2fa58d" />
        </button>
      </div>
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
// 可拖曳群組 Tab
// ══════════════════════════════════════════════════════════════════
function SortableGroupTab({
  group,
  isActive,
  isDefault,
  onSelect,
  onRename,
  onDelete,
  onSetDefault,
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: group.id,
  });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  const [editing, setEditing] = useState(false);
  const [value, setValue] = useState(group.name);

  function confirmEdit() {
    if (value.trim()) onRename(group.id, value.trim());
    setEditing(false);
  }

  return (
    <div ref={setNodeRef} style={style} className="d-flex align-items-center gap-4">
      {/* 拖曳把手 */}
      <span
        {...attributes}
        {...listeners}
        className="text-muted"
        style={{ cursor: 'grab', touchAction: 'none' }}
        title="拖曳排列群組"
      >
        <GripVertical size={14} />
      </span>

      {editing ? (
        <>
          <input
            className="form-control form-control-sm"
            style={{ width: 120 }}
            value={value}
            onChange={(e) => setValue(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && confirmEdit()}
            autoFocus
          />
          <button className="btn btn-sm btn-success" onClick={confirmEdit}>
            <Check size={12} />
          </button>
          <button className="btn btn-sm btn-secondary" onClick={() => setEditing(false)}>
            <X size={12} />
          </button>
        </>
      ) : (
        <>
          <button
            className={`btn btn-sm rounded-pill ${isActive ? 'btn-primary' : 'btn-outline-secondary'}`}
            onClick={() => onSelect(group.id)}
          >
            {group.name}
            {isDefault && <span className="ms-1 text-warning">★</span>}
          </button>
          <button
            className="btn btn-sm btn-link p-0 text-muted"
            title="改名"
            onClick={() => {
              setValue(group.name);
              setEditing(true);
            }}
          >
            <Pencil size={12} />
          </button>
          {!isDefault && (
            <button
              className="btn btn-sm btn-link p-0 text-muted"
              title="設為預設群組"
              onClick={() => onSetDefault(group.id)}
            >
              <BookmarkCheck size={12} />
            </button>
          )}
          <button
            className="btn btn-sm btn-link p-0 text-danger"
            title="刪除群組"
            onClick={() => {
              if (confirm(`確定刪除「${group.name}」群組？`)) onDelete(group.id);
            }}
          >
            <Trash2 size={12} />
          </button>
        </>
      )}
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
// 主元件
// ══════════════════════════════════════════════════════════════════
export default function MyWishlist() {
  const user = useSelector(authUser);
  const {
    wishlist,
    loading,
    toggleStock,
    addGroup,
    renameGroup,
    deleteGroup,
    setDefaultGroup,
    addStockToGroup,
    removeStockFromGroup,
    reorderStocks,
    reorderGroups,
  } = useWishlist();

  const [activeGroupId, setActiveGroupId] = useState(null);
  const [addSymbol, setAddSymbol] = useState('');
  const [showNewGroupInput, setShowNewGroupInput] = useState(false);
  const [newGroupName, setNewGroupName] = useState('');

  // 整理過的資料
  const groups = useMemo(() => {
    if (!wishlist?.groups) return [];
    return [...wishlist.groups].sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
  }, [wishlist?.groups]);

  const defaultGroup = useMemo(() => {
    if (!wishlist) return null;
    return wishlist.groups.find((g) => g.id === wishlist.defaultGroupId) || wishlist.groups[0];
  }, [wishlist]);

  const allStocks = useMemo(() => {
    if (!wishlist) return [];
    const set = new Set(wishlist.stocks);
    return wishlist.stockOrder.filter((s) => set.has(s));
  }, [wishlist]);

  // dnd-kit sensor：需拖曳 8px 才觸發，避免誤觸點擊
  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }));

  // 初始選中預設群組
  useEffect(() => {
    if (defaultGroup && activeGroupId === null) setActiveGroupId(defaultGroup.id);
  }, [defaultGroup?.id]);

  // ── 未登入 ──
  if (!user) {
    return (
      <div className="d-flex flex-column align-items-center justify-content-center py-80 gap-16">
        <Heart size={48} className="text-primary" />
        <p className="h5 font-zh-tw text-muted">請先登入才能使用自選股功能</p>
      </div>
    );
  }

  // ── 載入中 ──
  if (loading || !wishlist) {
    return (
      <div className="d-flex justify-content-center py-80">
        <BeatLoader color="var(--bs-primary)" />
      </div>
    );
  }

  // ── 顯示的股票 ──
  const displayStocks = activeGroupId
    ? allStocks.filter((s) =>
        groups.find((g) => g.id === activeGroupId)?.stockIds.includes(String(s))
      )
    : allStocks;

  // ── 股票拖曳結束 ──
  function handleStockDragEnd(event) {
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    const oldIdx = allStocks.indexOf(active.id);
    const newIdx = allStocks.indexOf(over.id);
    if (oldIdx === -1 || newIdx === -1) return;
    const newOrder = arrayMove(allStocks, oldIdx, newIdx);
    reorderStocks(newOrder);
  }

  // ── 群組拖曳結束 ──
  function handleGroupDragEnd(event) {
    const { active, over } = event;
    if (!over || active.id === over.id) return;

    const groupIds = groups.map((g) => g.id);
    const oldIdx = groupIds.indexOf(active.id);
    const newIdx = groupIds.indexOf(over.id);
    if (oldIdx === -1 || newIdx === -1) return;
    const newGroupIds = arrayMove(groupIds, oldIdx, newIdx);
    reorderGroups(newGroupIds);
  }

  function handleAddStock(e) {
    e.preventDefault();
    const sym = addSymbol.trim().toUpperCase();
    if (!sym) return;
    toggleStock(sym);
    setAddSymbol('');
  }

  function handleAddGroup() {
    if (newGroupName.trim()) {
      addGroup(newGroupName.trim());
      setNewGroupName('');
      setShowNewGroupInput(false);
    }
  }

  function handleRemoveFromGroup(groupId, symbol, isInGroup) {
    isInGroup ? removeStockFromGroup(groupId, symbol) : addStockToGroup(groupId, symbol);
  }

  return (
    <div className="py-24 py-lg-40">
      <h2 className="fs-bold mb-24 font-zh-tw h1-lg">我的好股</h2>

      {/* ── 群組 Tabs（可拖曳）── */}
      <DndContext
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragEnd={handleGroupDragEnd}
      >
        <SortableContext items={groups.map((g) => g.id)} strategy={horizontalListSortingStrategy}>
          <div className="d-flex flex-wrap align-items-center gap-8 mb-16">
            {/* 全部 tab（不可拖曳） */}
            <button
              className={`btn btn-sm rounded-pill ${!activeGroupId ? 'btn-primary' : 'btn-outline-secondary'}`}
              onClick={() => setActiveGroupId(null)}
            >
              全部
            </button>

            {groups.map((g) => (
              <SortableGroupTab
                key={g.id}
                group={g}
                isActive={activeGroupId === g.id}
                isDefault={g.id === defaultGroup?.id}
                onSelect={setActiveGroupId}
                onRename={renameGroup}
                onDelete={(id) => {
                  deleteGroup(id);
                  if (activeGroupId === id) setActiveGroupId(null);
                }}
                onSetDefault={setDefaultGroup}
              />
            ))}

            {/* 新增群組 */}
            {showNewGroupInput ? (
              <div className="d-flex align-items-center gap-4">
                <input
                  className="form-control form-control-sm"
                  style={{ width: 120 }}
                  placeholder="群組名稱"
                  value={newGroupName}
                  onChange={(e) => setNewGroupName(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleAddGroup()}
                  autoFocus
                />
                <button className="btn btn-sm btn-success" onClick={handleAddGroup}>
                  <Check size={12} />
                </button>
                <button
                  className="btn btn-sm btn-secondary"
                  onClick={() => setShowNewGroupInput(false)}
                >
                  <X size={12} />
                </button>
              </div>
            ) : (
              <button
                className="btn btn-sm btn-outline-primary rounded-pill"
                onClick={() => setShowNewGroupInput(true)}
              >
                <Plus size={14} /> 新增群組
              </button>
            )}
          </div>
        </SortableContext>
      </DndContext>

      {/* ── 快速加入收藏 ── */}
      <form className="d-flex gap-8 mb-16" onSubmit={handleAddStock}>
        <input
          className="form-control form-control-sm"
          style={{ maxWidth: 160 }}
          placeholder="輸入代碼，如 2330"
          value={addSymbol}
          onChange={(e) => setAddSymbol(e.target.value)}
        />
        <button type="submit" className="btn btn-sm btn-primary">
          <Plus size={14} /> 加入收藏
        </button>
      </form>

      {/* ── 股票清單（可拖曳）── */}
      {allStocks.length === 0 ? (
        <div className="text-center text-muted py-48 font-zh-tw">
          <Heart size={36} className="mb-16 text-primary" />
          <p>還沒有收藏任何股票</p>
        </div>
      ) : displayStocks.length === 0 && activeGroupId ? (
        <div className="text-center text-muted py-48 font-zh-tw">
          <p>此群組尚無股票</p>
        </div>
      ) : (
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragEnd={handleStockDragEnd}
        >
          <SortableContext items={displayStocks} strategy={verticalListSortingStrategy}>
            <div className="border rounded-3 overflow-hidden">
              {displayStocks.map((symbol) => (
                <SortableStockRow
                  key={symbol}
                  symbol={symbol}
                  groups={groups}
                  activeGroupId={activeGroupId}
                  onRemoveFromGroup={handleRemoveFromGroup}
                  onToggle={toggleStock}
                />
              ))}
            </div>
          </SortableContext>
        </DndContext>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { NavLink, useLocation, useNavigate } from 'react-router-dom';
import ButtonPrimary from '../Tools/ButtonPrimary';
import ButtonOutline from '../Tools/ButtonOutline';
import Logo from '../Tools/Logo';
import { Search, Menu, X } from 'lucide-react';
import { useDispatch, useSelector } from 'react-redux';
import { logoutThunk } from '../../app/features/auth/authThunks';
import { IsAuthed } from '../../app/features/auth/authSlice';
import SearchStock from '../Tools/SearchStock';
import axios from 'axios';

export default function Navbar() {
  const [isScrolled, setIsScrolled] = useState(false);
  const [searchId, setSearchId] = useState(''); // 新增搜尋狀態
  const isAuth = useSelector(IsAuthed);
  const dispatch = useDispatch();
  const location = useLocation();
  const navigate = useNavigate(); // 用來導向搜尋結果
  const StockUrl = import.meta.env.VITE_stocksUrl;
  const [symbols, setSymbols] = useState([]);

  const isIndex = location.pathname === '/';

  // 當 isScrolled 時，不論 isIndex 都使用相同的色系（白色）
  const navLogoColor = isScrolled ? 'text-white' : isIndex ? 'text-white' : 'text-primary';
  const navLinkColor = isScrolled ? 'text-white' : isIndex ? 'text-white' : 'text-gray-900';
  const navSearchColor = isScrolled
    ? 'bg-gray-50 text-gray-200 placeholder-gray-200'
    : isIndex
      ? 'bg-gray-50 text-gray-200 placeholder-gray-200'
      : 'bg-gray-400 text-gray-800 placeholder-gray-800';
  const navSearchBigScreen =
    'placeHover-WH font-weight-light border-0 round-8 py-12 ps-24 pe-16 shadow-none';
  const navSearchSmallScreen =
    'placeHover-BK bg-gray-400 text-gray-800 font-weight-light placeholder-gray-800 border-0 round-8 py-12 ps-24 pe-16 shadow-none';
  const navSearchBarBigScreen = 'text-white';
  const navSearchBarSmallScreen = 'text-gray-900';

  useEffect(() => {
    const handleScroll = () => {
      requestAnimationFrame(() => {
        const scrollY = window.scrollY || window.pageYOffset;
        isIndex ? setIsScrolled(scrollY > 200) : setIsScrolled(scrollY > 15);
      });
    };
    handleScroll();

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, [isIndex]); // 加入 isIndex

  const handleLogout = () => {
    dispatch(logoutThunk());
  };

  const openLogin = () => {
    navigate('/login');
  };

  const openRegist = () => {
    navigate('/regist');
  };

  const closeOffcanvas = () => {
    const offcanvasElement = document.getElementById('mobileMenu');
    if (offcanvasElement) {
      const closeBtn = offcanvasElement.querySelector('[data-bs-dismiss="offcanvas"]');
      if (closeBtn) closeBtn.click();
    }
  };

  // 新增：搜尋按鈕或 Enter 鍵事件
  const handleSearch = (e) => {
    e.preventDefault();
    if (searchId.trim() !== '') {
      navigate(`/stockInfo/${searchId.trim()}`);
      setSearchId(''); // 清空輸入框
      closeOffcanvas(); // 如果是小螢幕，關閉側邊欄
    }
  };
  const getDatas = async () => {
    try {
      const response = await axios.get(StockUrl);
      const rawData = Array.isArray(response?.data?.data) ? response.data.data : [];
      const filteredData = rawData.filter(
        (item) => Array.isArray(item?.prices) && item.prices.length > 3
      );
      const mapFilteredData = filteredData.map((item) => ({
        symbol: item.id,
        name: item.name,
      }));
      setSymbols(mapFilteredData);
      // //console.log('股票資料:', mapFilteredData);
    } catch (error) {
      console.error('獲取股票資料失敗:', error);
    }
  };

  useEffect(() => {
    getDatas();
  }, []);
  return (
    <>
      <nav
        className={`navbar navbar-expand-lg position-fixed top-0 start-0 end-0 p-12 py-lg-16 font-zh-tw transition-all ${
          isScrolled ? 'navbar-scrolled' : ''
        }`}
        style={{ zIndex: 500 }}
        data-bs-theme="dark"
      >
        <div className="container d-flex gap-md-48 justify-content-between px-0 ">
          <NavLink className="navbar-brand" to="/">
            <Logo className={`nav-logo ${navLogoColor}`} />
          </NavLink>

          {/* 註冊/使用者資料按鈕 */}
          <ButtonPrimary
            className="w-auto py-10 px-24 d-lg-none"
            onClick={isAuth ? undefined : openRegist}
          >
            {isAuth ? '使用者資料' : '免費註冊'}
          </ButtonPrimary>

          {/* 大螢幕搜尋框 */}
          <div className="w-100 d-none d-lg-block">
            <SearchStock
              symbols={symbols}
              onSelect={(item) => {
                // //console.log('你選到的股票:', item);
                navigate(`/stockInfo/${item.symbol}`);
              }}
              navSearchColor={navSearchColor}
              navSearchScreen={navSearchBigScreen}
              navSearchBarScreen={navSearchBarBigScreen}
            />
          </div>
          {/* <form
            className="d-none position-relative d-lg-flex w-100"
            onSubmit={handleSearch} // form submit 導向
          >
            <input
              type="text"
              className={`form-control ${navSearchColor} placeHover-WH font-weight-light border-0 round-8 py-12 ps-24 pe-16 shadow-none`}
              placeholder="輸入台/美股代號，查看公司價值"
              value={searchId}
              onChange={(e) => setSearchId(e.target.value)}
            />
            <button
              type="submit"
              className="position-absolute end-0 top-50 translate-middle-y me-12 text-white bg-transparent border-0"
            >
              <Search size={24} className={navLinkColor} />
            </button>
          </form> */}

          {/* 大螢幕導覽 */}
          <ul className="navbar-nav w-100 d-none d-lg-flex gap-md-8">
            <li className="nav-item d-flex flex-column justify-content-center align-items-center">
              <NavLink className={`nav-link py-10 px-16 ${navLinkColor}`} to="/mystocklist">
                我的選股清單
              </NavLink>
            </li>
            <li className="nav-item">
              <NavLink className={`nav-link py-10 px-16 ${navLinkColor}`} to="/topics">
                熱門話題
              </NavLink>
            </li>
            <li className="nav-item">
              {isAuth ? (
                <button
                  className={`nav-link btn btn-link ${navLinkColor} py-10 px-16 border-0 shadow-none`}
                  onClick={handleLogout}
                >
                  登出
                </button>
              ) : (
                <button
                  className={`nav-link btn btn-link ${navLinkColor} py-10 px-16 border-0 shadow-none`}
                  onClick={openLogin}
                >
                  登入
                </button>
              )}
            </li>
            <ButtonPrimary className="w-auto py-10 px-32" onClick={isAuth ? undefined : openRegist}>
              {isAuth ? '使用者資料' : '免費註冊'}
            </ButtonPrimary>
          </ul>

          {/* 漢堡按鈕 */}
          <button
            className="navbar-toggler border-0"
            type="button"
            data-bs-toggle="offcanvas"
            data-bs-target="#mobileMenu"
          >
            <Menu className={navLogoColor} />
          </button>
        </div>
      </nav>

      {/* 小螢幕側邊 */}
      <div
        className="offcanvas d-lg-none offcanvas-start w-100 border-0"
        tabIndex="-1"
        id="mobileMenu"
        data-bs-theme="light"
      >
        <div className="offcanvas-header bg-white border-bottom py-12 px-12">
          <Logo className="header-logo" />
          <button
            type="button"
            className="icon-40 btn-close text-reset shadow-none border-0 d-flex align-items-center justify-content-center"
            data-bs-dismiss="offcanvas"
          >
            <X size={24} />
          </button>
        </div>

        {/* 小螢幕搜尋框 */}
        <div className="mb-40 px-12">
          <SearchStock
            symbols={symbols}
            onSelect={(item) => {
              // //console.log('你選到的股票:', item);
              navigate(`/stockInfo/${item.symbol}`);
            }}
            navSearchColor={navSearchColor}
            navSearchScreen={navSearchSmallScreen}
            navSearchBarScreen={navSearchBarSmallScreen}
          />
        </div>
        {/* <form className="position-relative mb-40 px-12" onSubmit={handleSearch}>
          <input
            type="text"
            className="form-control placeHover-BK bg-gray-400 text-gray-800 font-weight-light placeholder-gray-800 border-0 round-8 py-12 ps-24 pe-16 shadow-none"
            placeholder="輸入台/美股代號，查看公司價值"
            value={searchId}
            onChange={(e) => setSearchId(e.target.value)}
          />
          <button
            type="submit"
            className="position-absolute end-0 top-50 translate-middle-y me-12 text-gray-800 bg-transparent border-0"
          >
            <Search size={24} />
          </button>
        </form> */}

        {/* 小螢幕選單 */}
        <ul className="navbar-nav font-zh-tw text-center gap-24 h6 px-12">
          <li className="nav-item py-10 px-16">
            <NavLink
              to="/mystocklist"
              className="text-decoration-none text-gray-900"
              onClick={closeOffcanvas}
            >
              我的選股清單
            </NavLink>
          </li>
          <li className="nav-item py-10 px-16">
            <NavLink
              to="/topics"
              className="text-decoration-none text-gray-900"
              onClick={closeOffcanvas}
            >
              熱門話題
            </NavLink>
          </li>
        </ul>

        <div className="mt-auto d-flex gap-12 flex-column font-zh-tw px-12">
          {isAuth ? (
            <ButtonOutline
              className="py-10 px-32"
              onClick={() => {
                handleLogout();
                closeOffcanvas();
              }}
            >
              登出
            </ButtonOutline>
          ) : (
            <ButtonOutline
              className="py-10 px-32"
              onClick={() => {
                closeOffcanvas();
                openLogin();
              }}
            >
              登入
            </ButtonOutline>
          )}
          <ButtonPrimary
            className="py-10 px-32 mb-24"
            onClick={() => {
              closeOffcanvas();
              openRegist();
            }}
          >
            免費註冊
          </ButtonPrimary>
        </div>
      </div>
    </>
  );
}

