export default function StockCard() {
  const [stocks, setStocks] = useState([]);
  const [primaryColor, setPrimaryColor] = useState('#0d6efd');
  const isAuth = useSelector(IsAuthed);
  const navigate = useNavigate();
  const dispatch = useDispatch();

  useEffect(() => {
    const fetchData = async () => {
      dispatch(loadingStarted({ status: 'home.global' }));
      try {
        const baseURL = import.meta.env.VITE_API_BASE;

        const res = await axios.get(`${baseURL}/symbols?_embed=prices&_limit=1000`);

        const symbolsWithPrices = res.data.data
          .filter((s) => s.prices?.length)
          .map((s) => {
            const sorted = [...s.prices].sort((a, b) => new Date(b.date) - new Date(a.date));
            return { ...s, latestPrice: sorted[0] };
          });

        setStocks(symbolsWithPrices);
      } catch (e) {
        console.error('讀取資料失敗', e);
      } finally {
        dispatch(loadingStopped({ status: 'home.global' }));
      }
    };
    fetchData();
  }, [dispatch]);

  useEffect(() => {
    const color = getComputedStyle(document.documentElement)
      .getPropertyValue('--bs-primary')
      .trim();
    if (color) setPrimaryColor(color);
  }, []);

  return (
    <section className="bg-gray-400">
      <div className="container py-64 py-md-96 font-zh-tw">
        <h3 className="h2-md mb-8">熱門個股</h3>
        <h2 className="text-primary display-2 display-1-md mb-32 mb-md-40">Popular Stocks</h2>

        <Swiper
          modules={[Pagination, Grid, Navigation]}
          pagination={{
            el: '.stock-pagination',
            clickable: true,
            renderBullet: (index, className) => `<span class="${className}">${index + 1}</span>`,
          }}
          navigation={{
            prevEl: '.stock-prev',
            nextEl: '.stock-next',
          }}
          spaceBetween={10}
          slidesPerView={1}
          slidesPerGroup={3}
          grid={{ rows: 4, fill: 'row' }}
          breakpoints={{
            1024: {
              slidesPerView: 2,
              slidesPerGroup: 4,
              spaceBetween: 20,
              grid: { rows: 2, fill: 'row' },
            },
          }}
          className="stockSwiper"
        >
          {stocks.map((stock, index) => {
            const price = stock.latestPrice;
            const changePct = price?.dailyChangePct ?? 0;
            const totalPct = price?.totalChangePct ?? 0;

            const trend = changePct > 0 ? 'up' : changePct < 0 ? 'down' : 'flat';

            const trendColor =
              trend === 'up' ? 'text-danger' : trend === 'down' ? 'text-success' : 'text-secondary';

            const trendBgColor =
              trend === 'up' ? 'bg-pink' : trend === 'down' ? 'bg-pinkgreen' : 'border bg-light';

            // 前4張可看，其餘未登入模糊
            const shouldBlur = !isAuth && index >= 4;

            return (
              <SwiperSlide key={stock.id} className={shouldBlur ? 'position-relative' : ''}>
                <div
                  className="stockCard border round-24 p-16 d-md-flex justify-content-md-between py-md-48 px-md-24"
                  style={
                    shouldBlur
                      ? { filter: 'blur(8px)', pointerEvents: 'none' }
                      : { cursor: 'pointer' }
                  }
                  onClick={() => {
                    if (!shouldBlur) {
                      navigate(`/stockInfo/${stock.id}`);
                    }
                  }}
                >
                  {/* 上半部 */}
                  <div className="d-flex justify-content-between align-items-center border-bottom pb-8 mb-8 pb-md-0 mb-md-0 border-md-0">
                    <div className="d-flex gap-16 align-items-center me-md-16">
                      <div
                        className={`d-flex justify-content-center align-items-center icon-48 round-8 ${trendBgColor}`}
                      >
                        {trend === 'up' && <ArrowUp className={`icon-24 ${trendColor}`} />}
                        {trend === 'down' && <ArrowDown className={`icon-24 ${trendColor}`} />}
                        {trend === 'flat' && <Minus className={`icon-24 ${trendColor}`} />}
                      </div>
                      <h3>{stock.name}</h3>
                    </div>
                    <div className="font-weight-light round-4 bg-gray-500 py-10 px-8">
                      {stock.id} 上市
                    </div>
                  </div>

                  {/* 價格區 */}
                  <div className="d-flex justify-content-between align-items-center flex-md-column gap-md-8">
                    <div className={`h1 ${trendColor}`}>
                      {(price?.close ?? 0).toLocaleString(undefined, {
                        minimumFractionDigits: 2,
                        maximumFractionDigits: 2,
                      })}
                    </div>
                    <div className={`caption ${trendColor}`}>
                      {trend === 'up' && '+'}
                      {changePct.toFixed(2)}% ({totalPct.toFixed(2)}%)
                    </div>
                  </div>
                </div>

                {/* 未登入遮罩 */}
                {shouldBlur && (
                  <div
                    className="position-absolute top-50 start-50 translate-middle text-center"
                    style={{ zIndex: 10 }}
                  >
                    <ButtonPrimary
                      className="btn btn-outline-primary py-12 px-32 round-8"
                      onClick={() => navigate('/login')}
                    >
                      登入查看更多
                    </ButtonPrimary>
                  </div>
                )}
              </SwiperSlide>
            );
          })}
        </Swiper>

        {/* 分頁控制 */}
        <div className="stock-pagination-container justify-content-md-start d-flex align-items-center gap-16 mt-24">
          <div className="stock-prev cursor-pointer">
            <ChevronLeft size={24} />
          </div>
          <div className="stock-pagination"></div>
          <div className="stock-next cursor-pointer">
            <ChevronRight size={24} />
          </div>
        </div>
      </div>
    </section>
  );
}

import axios from 'axios';
import { useEffect, useState } from 'react';
import { createChart, LineSeries } from 'lightweight-charts';
import dayjs from 'dayjs';

const AllIndexChart = ({ indexId = 't24' }) => {
  const [indexData, setIndexData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [chartMode, setChartMode] = useState('realtime'); // 'realtime' 跟 'static'
  const indexList = [
    { id: 't02', name: '食品類指數' },
    { id: 't13', name: '電子類指數' },
    { id: 't17', name: '金融保險類指數' },
    { id: 't22', name: '生技醫療類指數' },
    { id: 't24', name: '半導體類指數' },
    { id: 't30', name: '資訊服務類指數' },
  ];

  useEffect(() => {
    const getIndexData = async () => {
      try {
        const now = dayjs();
        const response = await axios.get(
          `https://backend.taiwanindex.com.tw/api/indexes/${indexId}/records?start=2020-01-01&end=${now.format('YYYY-MM-DD')}`
        );
        // //console.log(response.data);
        const indexData = [
          {
            last_date: response.data.last_date,
            data: response.data.data.datasets[0].data,
            label: response.data.data.datasets[0].label,
            value_type: response.data.data.datasets[0].value_type,
            date: response.data.data.labels,
          },
        ];
        // //console.log('由原始資料轉錄', indexData[0]);
        setIndexData(indexData[0]);
        setLoading(false);
      } catch (error) {
        console.error(error);
      }
    };
    getIndexData();
  }, [indexId]);
  // //console.log('indexData', indexData, typeof indexData);

  // tradingViewChart
  useEffect(() => {
    if (!indexData || !indexData.date || !indexData.data) return;

    // 處理資料：將日期陣列和數值陣列配對
    const formattedPoints = indexData.date
      .map((dateStr, index) => {
        // dateStr 格式為 'YYYY-MM-DD'
        const date = dayjs(dateStr);
        const value = parseFloat(indexData.data[index]);

        return {
          time: date.format('YYYY-MM-DD'), // lightweight-charts 接受 'YYYY-MM-DD' 格式
          value: value,
        };
      })
      .filter((p) => {
        // 條件：數值有效
        return !isNaN(p.value) && p.time;
      });

    // //console.log('有效資料數:', formattedPoints.length);
    // //console.log('圖表模式:', chartMode);

    if (formattedPoints.length === 0) return;

    const container = document.getElementById('taiwan-index-chart-container');
    if (!container) return;
    container.innerHTML = ''; // 清空舊圖表

    const chart = createChart(container, {
      width: container.clientWidth,
      height: 400,
      layout: { background: { color: '#ffffff' }, textColor: '#333' },
      grid: {
        vertLines: { color: '#f0f0f0' },
        horzLines: { color: '#f0f0f0' },
      },
      timeScale: {
        timeVisible: true,
        secondsVisible: false, // 日線圖不需要秒數

        // 底部刻度的格式化
        tickMarkFormatter: (time) => {
          // time 為 'YYYY-MM-DD' 字串
          return dayjs(time).format('YYYY-MM-DD');
        },
      },

      // 十字線 tooltip
      localization: {
        timeFormatter: (time) => {
          // time 為 'YYYY-MM-DD' 字串
          return dayjs(time).format('YYYY/MM/DD');
        },
      },
    });

    const lineSeries = chart.addSeries(LineSeries, {
      color: '#2962FF',
      lineWidth: 2,
    });

    let intervalId = null;

    if (chartMode === 'realtime') {
      // 動態模式：逐日顯示
      let currentIndex = 0;
      lineSeries.setData([formattedPoints[0]]);
      currentIndex = 1;

      intervalId = setInterval(() => {
        if (currentIndex < formattedPoints.length) {
          lineSeries.update(formattedPoints[currentIndex]);
          currentIndex++;
        } else {
          clearInterval(intervalId);
        }
      }, 50); // 設定速度來展現動畫效果
    } else {
      // 靜態模式：顯示所有日線資料
      lineSeries.setData(formattedPoints);
      chart.timeScale().setVisibleRange({
        from: formattedPoints[0].time,
        to: formattedPoints.at(-1).time,
      });
    }

    const handleResize = () => {
      chart.applyOptions({ width: container.clientWidth });
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      if (intervalId) clearInterval(intervalId);
      chart.remove();
    };
  }, [indexData, chartMode]); // 加入 chartMode

  return (
    <div className="p-24">
      <h2 className="mb-16 d-flex justify-content-between">
        {indexList.find((item) => item.id === indexId)?.name}
        <span className="caption">
          {chartMode === 'realtime' ? indexData.last_date : indexData.last_date}
        </span>
      </h2>
      <div id="taiwan-index-chart-container" className="w-100 mb-24 mb-lg-48"></div>
      <div className="d-flex justify-content-center gap-24 gap-lg-96">
        <button
          type="button"
          className={`btn py-lg-16 px-lg-24 ${chartMode === 'realtime' ? 'btn-primary text-white' : 'btn-outline-primary'}`}
          onClick={() => setChartMode('realtime')}
        >
          動態顯示(每日)
        </button>
        <button
          type="button"
          className={`btn py-lg-16 px-lg-24 ${chartMode === 'static' ? 'btn-primary text-white' : 'btn-outline-primary'}`}
          onClick={() => setChartMode('static')}
        >
          整體線圖
        </button>
      </div>
    </div>
  );
};

export default AllIndexChart;

