import axios from 'axios';
import { useEffect, useState } from 'react';
import { createChart, LineSeries } from 'lightweight-charts';
import dayjs from 'dayjs';

const TaiwanIndexChart = () => {
  const [taiwanIndexData, setTaiwanIndexData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [chartMode, setChartMode] = useState('realtime'); // 'realtime' 跟 'static'

  useEffect(() => {
    const testGetFromStock = async () => {
      try {
        const response = await axios.get(
          'https://www.twse.com.tw/rwd/zh/TAIEX/MI_5MINS_INDEX?response=json&_=1770530872584'
        );
        // //console.log(response.data);
        const taiex = [
          {
            title: response.data.title,
            date: response.data.date,
            tablehead: [response.data.fields[0], response.data.fields[1]],
            tabledata: response.data.data.map((item) => {
              return {
                time: item[0],
                value: item[1],
              };
            }),
          },
        ];
        setTaiwanIndexData(taiex);
        // //console.log(taiex);
      } catch (error) {
        console.error(error);
      }
    };
    testGetFromStock();
  }, []);

  //   tradingViewChart
  useEffect(() => {
    if (taiwanIndexData.length === 0) return;

    const dataObj = taiwanIndexData[0];
    const baseDate = dayjs(dataObj.date, 'YYYYMMDD'); // 使用 dayjs 日期

    // 取得開盤時間（第一筆資料的時間）
    const openingTime = dataObj.tabledata[0].time; //  "09:00:00"
    const closingTime = dataObj.tabledata[dataObj.tabledata.length - 1].time; // 收盤時間

    // //console.log('開盤時間:', openingTime);
    // //console.log('收盤時間:', closingTime);

    // 處理資料
    const formattedPoints = dataObj.tabledata
      .map((item) => {
        // 使用 dayjs 結合日期與時間（不加時區偏移，使用本地時間）
        const pointTime = dayjs(`${baseDate.format('YYYY-MM-DD')} ${item.time}`);
        const value = parseFloat(item.value.replace(/,/g, ''));

        return {
          time: pointTime.unix(),
          value: value,
          rawTime: item.time,
        };
      })
      .filter((p) => {
        // 條件：時間有效 && 數值有效 && 時間在開盤到收盤之間
        return (
          !isNaN(p.time) && !isNaN(p.value) && p.rawTime >= openingTime && p.rawTime <= closingTime
        );
      });

    // //console.log('有效資料數:', formattedPoints.length);
    // //console.log('圖表模式:', chartMode);

    if (formattedPoints.length === 0) return;

    const container = document.getElementById('taiwan-index-chart-container');
    if (!container) return;
    container.innerHTML = ''; // 清空舊圖表

    const fmtTW = (unixSec, withSeconds = true) => {
      const opt = {
        timeZone: 'Asia/Taipei',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false,
      };
      if (withSeconds) opt.second = '2-digit';

      return new Intl.DateTimeFormat('zh-TW', opt).format(new Date(unixSec * 1000));
    };

    const chart = createChart(container, {
      width: container.clientWidth,
      height: 400,
      layout: { background: { color: '#ffffff' }, textColor: '#333' },
      grid: {
        vertLines: { color: '#f0f0f0' },
        horzLines: { color: '#f0f0f0' },
      },
      timeScale: {
        timeVisible: true,
        secondsVisible: chartMode === 'realtime', // 動態模式顯示秒數

        // 底部刻度的格式化
        tickMarkFormatter: (time) => {
          // time 物件
          const unixSec =
            typeof time === 'number'
              ? time
              : Math.floor(new Date(time.year, time.month - 1, time.day).getTime() / 1000);

          return fmtTW(unixSec, chartMode === 'realtime');
        },
      },

      // 十字線 tooltip
      localization: {
        timeFormatter: (time) => fmtTW(time, chartMode === 'realtime'),
      },
    });

    const lineSeries = chart.addSeries(LineSeries, {
      color: '#2962FF',
      lineWidth: 2,
    });

    let intervalId = null;

    if (chartMode === 'realtime') {
      let currentIndex = 0;
      lineSeries.setData([formattedPoints[0]]);
      currentIndex = 1;

      intervalId = setInterval(() => {
        if (currentIndex < formattedPoints.length) {
          lineSeries.update(formattedPoints[currentIndex]);
          currentIndex++;
        } else {
          clearInterval(intervalId);
        }
      }, 100); // 設定速度來展現動畫效果
    } else {
      // 靜態模式：每1分鐘取一筆資料
      const oneMinuteData = formattedPoints.filter((point) => {
        // 只保留秒數為 :00 的資料點（即每分鐘的整點）
        return point.rawTime.endsWith(':00');
      });

      //   //console.log('靜態模式資料點數（每1分鐘）:', oneMinuteData.length);

      lineSeries.setData(oneMinuteData);
      chart.timeScale().setVisibleRange({
        from: oneMinuteData[0].time,
        to: oneMinuteData.at(-1).time,
      });
    }

    const handleResize = () => {
      chart.applyOptions({ width: container.clientWidth });
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      if (intervalId) clearInterval(intervalId);
      chart.remove();
    };
  }, [taiwanIndexData, chartMode]); // 加入 chartMode

  return (
    <div className="p-24">
      {taiwanIndexData.length > 0 && (
        <>
          <h2 className="mb-16 d-flex justify-content-between">
            {taiwanIndexData[0].tablehead[1]}{' '}
            <span className="caption">
              {chartMode === 'realtime'
                ? taiwanIndexData[0].title
                : `${dayjs(taiwanIndexData[0].date).format('YYYY/MM/DD')}`}
            </span>
          </h2>
        </>
      )}
      <div id="taiwan-index-chart-container" className="w-100 mb-24 mb-lg-48"></div>
      <div className="d-flex justify-content-center gap-24 gap-lg-96">
        <button
          type="button"
          className={`btn py-lg-16 px-lg-24 ${chartMode === 'realtime' ? 'btn-primary text-white' : 'btn-outline-primary'}`}
          onClick={() => setChartMode('realtime')}
        >
          動態顯示:每5秒
        </button>
        <button
          type="button"
          className={`btn py-lg-16 px-lg-24 ${chartMode === 'static' ? 'btn-primary text-white' : 'btn-outline-primary'}`}
          onClick={() => setChartMode('static')}
        >
          整體線圖
        </button>
      </div>
    </div>
  );
};

export default TaiwanIndexChart;

// TradingChart1.jsx
import React, { useMemo } from 'react';
import dayjs from 'dayjs';

/**
 * lightweight-charts-react-components 元件說明：
 *
 * 1. Chart - 主圖表容器
 *    - Props: options (圖表配置), containerProps (容器樣式)
 *    - Children: TimeScale, Pane (可多個), Series
 *
 * 2. Pane - 圖表面板/窗格（用於分隔不同指標）
 *    - Props: stretchFactor (面板高度比例，數字越大佔比越高)
 *    - Children: CandlestickSeries, LineSeries, HistogramSeries
 *
 * 3. CandlestickSeries - K線/蠟燭圖系列
 *    - Props: data (OHLC資料陣列), options (樣式配置)
 *    - Data格式: [{ time: 'YYYY-MM-DD', open, high, low, close }]
 *    - Children: 無
 *
 * 4. LineSeries - 折線圖系列
 *    - Props: data (線圖資料陣列), options (樣式配置)
 *    - Data格式: [{ time: 'YYYY-MM-DD', value }]
 *    - Children: PriceLine (可多個，用於標示水平線)
 *
 * 5. HistogramSeries - 柱狀圖系列（常用於成交量）
 *    - Props: data (柱狀圖資料陣列), options (樣式配置)
 *    - Data格式: [{ time: 'YYYY-MM-DD', value, color? }]
 *    - Children: 無
 *
 * 6. PriceLine - 價格水平線（用於標示關鍵價位）
 *    - Props: price (價格值), options (線條樣式)
 *    - 必須放在 LineSeries 內
 *    - Children: 無
 *
 * 7. TimeScale - 時間軸控制器
 *    - Props: 無
 *    - Children: TimeScaleFitContentTrigger
 *
 * 8. TimeScaleFitContentTrigger - 自動調整時間軸
 *    - Props: deps (依賴陣列，類似 useEffect)
 *    - Children: 無
 *
 */
import {
  CandlestickSeries,
  Chart,
  HistogramSeries,
  TimeScale,
  TimeScaleFitContentTrigger,
  Pane,
} from 'lightweight-charts-react-components';

// ---- Colors ----
const colors = {
  blue: '#2962FF',
  blue100: '#82B1FF',
  green: '#26a69a',
  red: '#ef5350',
  orange100: '#FFB74D',
  violet: '#9C27B0',
  gray100: '#E0E0E0',
};

// ---- Helper functions ----
/**
 * 從 stockData 提取 OHLC (開高低收) 蠟燭圖資料
 * @param {Object} stockData - 股票資料物件
 * @returns {Array} 格式: [{ time, open, high, low, close }]
 */
const generateOHLCData = (stockData) => {
  if (!stockData?.prices || stockData.prices.length === 0) {
    // //console.log('generateOHLCData: 沒有股票資料');
    return [];
  }
  // //console.log('generateOHLCData: 產生 K線資料', '，共', stockData.prices.length, '筆');

  return stockData.prices.map((price) => {
    return {
      time: price.date,
      open: price.open,
      high: price.high,
      low: price.low,
      close: price.close,
    };
  });
};

export default function TradingChart1({ stockData, stockSelect }) {
  /**
   * 使用 useMemo 只在組件初次渲染時生成資料
   * 避免每次 re-render 都重新計算
   */
  // //console.log('由父層來的資料', stockData);
  // //console.log('由父層來的資料', stockSelect);

  const { ohlcData, volumeData } = useMemo(() => {
    // 1. 生成 OHLC 資料從 stockData
    const ohlc = generateOHLCData(stockData);

    // 2. 如果沒有資料，返回空陣列
    if (ohlc.length === 0) {
      return { ohlcData: [], volumeData: [] };
    }

    // 3. 生成成交量資料（使用真實的 volume 數據）
    // 根據 K線紅綠設定顏色（收盤 > 開盤 = 紅色，否則綠色）
    const volume = stockData.prices.map((price) => {
      return {
        time: price.date,
        value: price.volume,
        color: price.close > price.open ? `${colors.red}90` : `${colors.green}90`,
      };
    });

    // //console.log('生成成交量資料:', volume.length, '筆，範例:', volume[0]);

    return { ohlcData: ohlc, volumeData: volume };
  }, [stockData, stockSelect]);

  // 早期返回：如果沒有資料，顯示提示訊息
  if (!stockData || !stockData.prices || stockData.prices.length === 0) {
    return (
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          width: '100%',
          height: '100%',
          color: '#666',
        }}
      >
        無可用的股票資料
      </div>
    );
  }

  if (ohlcData.length === 0) {
    return (
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          width: '100%',
          height: '100%',
          color: '#666',
        }}
      >
        資料處理失敗
      </div>
    );
  }

  return (
    // Chart: 主圖表容器
    <Chart
      options={{
        layout: {
          panes: {
            enableResize: true, // 允許拖曳調整面板高度
            separatorColor: colors.gray100, // 面板間分隔線顏色
          },
        },
      }}
      containerProps={{ style: { flexGrow: '1' } }} // 讓圖表填滿父容器
    >
      {/* TimeScale: 時間軸控制 */}
      <TimeScale>
        {/* 自動調整時間軸以顯示所有資料 */}
        <TimeScaleFitContentTrigger deps={[]} />
      </TimeScale>

      {/* Pane 1: 主圖 - K線圖 (高度比例 3) */}
      <Pane stretchFactor={3}>
        {/* CandlestickSeries: K線圖 */}
        <CandlestickSeries
          data={ohlcData}
          options={{
            upColor: colors.red, // 漲K內部顏色（透明 = 空心）
            downColor: colors.green, // 跌K內部顏色（實心橘）
            borderUpColor: colors.red, // 漲K邊框顏色（藍）
            borderDownColor: colors.green, // 跌K邊框顏色（橘）
            wickUpColor: colors.red, // 漲K上下影線顏色
            wickDownColor: colors.green, // 跌K上下影線顏色
            priceLineVisible: false, // 隱藏價格線
          }}
        />
      </Pane>

      {/* Pane 3: 成交量 (高度比例 1) */}
      <Pane stretchFactor={1}>
        {/* HistogramSeries: 成交量柱狀圖 */}
        <HistogramSeries
          data={volumeData}
          options={{
            priceLineVisible: false, // 隱藏價格線
          }}
        />
      </Pane>
    </Chart>
  );
}

import React, { createContext, useContext, useState, useCallback } from 'react';
import { api } from '../app/features/auth/authAPI';
import { useDispatch, useSelector } from 'react-redux';
import { authUser } from '../app/features/auth/authSlice';
import { pushMessage } from '../app/features/message/messageSlice';

const WishlistContext = createContext(null);

export const WishlistProvider = ({ children }) => {
  const [wishlist, setWishlist] = useState(null);
  const [loading, setLoading] = useState(false);
  const user = useSelector(authUser);
  const dispatch = useDispatch();

  // 1. 取得清單
  const getWishlist = useCallback(async (userId) => {
    if (!userId) return;
    setLoading(true);
    try {
      const res = await api.get(`/watchlists?userId=${userId}`);
      const data = res.data?.data?.[0];

      if (!data) {
        // 首次登入，建立預設資料
        const defaultGroupId = Math.random().toString(36).slice(2, 10);
        const newDoc = {
          userId,
          stocks: ['2330', '0050'],
          stockOrder: ['2330', '0050'],
          defaultGroupId,
          groups: [
            {
              id: defaultGroupId,
              name: '預設清單',
              stockIds: ['2330', '0050'],
              order: 0,
            },
          ],
        };
        const createRes = await api.post('/watchlists', newDoc);
        setWishlist(createRes.data?.data || createRes.data);
      } else {
        setWishlist(data);
      }
    } catch (err) {
      console.error('Failed to fetch wishlist', err);
    } finally {
      setLoading(false);
    }
  }, []);

  // 2. 切換收藏 (Axios PATCH -> GET)
  const toggleStock = async (symbol, targetGroupId = null) => {
    if (!user) {
      dispatch(pushMessage({ type: 'error', title: '請先登入後再收藏', timer: 3000 }));
      return;
    }
    if (!wishlist) return;

    const symbolStr = String(symbol);
    const stocks = [...wishlist.stocks];
    const stockOrder = [...wishlist.stockOrder];
    const groups = wishlist.groups.map((g) => ({ ...g, stockIds: [...g.stockIds] }));
    const idx = stocks.indexOf(symbolStr);

    if (idx === -1) {
      // 1. 加入總清單
      stocks.push(symbolStr);
      stockOrder.push(symbolStr);

      // 2. 決定加入哪個群組
      let selectedGroupId = targetGroupId;
      if (!selectedGroupId) {
        // 如果沒指定，預設存入第一個（通常是「預設清單」）
        selectedGroupId = wishlist.defaultGroupId || groups[0]?.id;
      }

      const targetGroup = groups.find((g) => g.id === selectedGroupId);
      if (targetGroup && !targetGroup.stockIds.includes(symbolStr)) {
        targetGroup.stockIds.push(symbolStr);
      }
    } else {
      // 取消收藏
      stocks.splice(idx, 1);
      const orderIdx = stockOrder.indexOf(symbolStr);
      if (orderIdx !== -1) stockOrder.splice(orderIdx, 1);
      // 同時從所有群組移除
      groups.forEach((g) => {
        g.stockIds = g.stockIds.filter((id) => String(id) !== symbolStr);
      });
    }

    try {
      await api.patch(`/watchlists/${wishlist.id}`, {
        stocks,
        stockOrder,
        groups,
      });
      // 直接重新獲取最新資料，確保穩定
      await getWishlist(user.id);
    } catch (err) {
      dispatch(pushMessage({ type: 'error', title: '操作失敗', timer: 3000 }));
    }
  };

  // 3. 檢查是否已收藏 (便利方法)
  const isWatched = useCallback(
    (symbol) => {
      if (!wishlist?.stocks) return false;
      return wishlist.stocks.includes(String(symbol));
    },
    [wishlist]
  );

  // 4. 群組與排序操作 (Axios PATCH -> GET)
  const addGroup = async (name) => {
    if (!wishlist) return;
    const newGroup = {
      id: Math.random().toString(36).slice(2, 10),
      name,
      stockIds: [],
      order: wishlist.groups.length,
    };
    const groups = [...wishlist.groups, newGroup];
    await updateWishlistRaw({ groups });
  };

  const renameGroup = async (groupId, name) => {
    if (!wishlist) return;
    const groups = wishlist.groups.map((g) => (g.id === groupId ? { ...g, name } : g));
    await updateWishlistRaw({ groups });
  };

  const deleteGroup = async (groupId) => {
    if (!wishlist) return;
    let groups = wishlist.groups.filter((g) => g.id !== groupId);
    let defaultGroupId = wishlist.defaultGroupId;
    if (defaultGroupId === groupId) {
      defaultGroupId = groups[0]?.id || null;
    }
    await updateWishlistRaw({ groups, defaultGroupId });
  };

  const setDefaultGroup = async (groupId) => {
    await updateWishlistRaw({ defaultGroupId: groupId });
  };

  const addStockToGroup = async (groupId, symbol) => {
    if (!wishlist) return;
    const groups = wishlist.groups.map((g) => {
      if (g.id === groupId && !g.stockIds.includes(String(symbol))) {
        return { ...g, stockIds: [...g.stockIds, String(symbol)] };
      }
      return g;
    });
    await updateWishlistRaw({ groups });
  };

  const removeStockFromGroup = async (groupId, symbol) => {
    if (!wishlist) return;
    const groups = wishlist.groups.map((g) => {
      if (g.id === groupId) {
        return { ...g, stockIds: g.stockIds.filter((id) => String(id) !== String(symbol)) };
      }
      return g;
    });
    await updateWishlistRaw({ groups });
  };

  const reorderStocks = async (newOrder) => {
    await updateWishlistRaw({ stockOrder: newOrder });
  };

  const reorderGroups = async (newGroupIds) => {
    if (!wishlist) return;
    const map = Object.fromEntries(wishlist.groups.map((g) => [g.id, g]));
    const groups = newGroupIds
      .filter((id) => map[id])
      .map((id, idx) => ({ ...map[id], order: idx }));
    await updateWishlistRaw({ groups });
  };

  const updateWishlistRaw = async (updates) => {
    if (!wishlist?.id || !user?.id) return;
    try {
      await api.patch(`/watchlists/${wishlist.id}`, updates);
      await getWishlist(user.id);
    } catch (err) {
      dispatch(pushMessage({ type: 'error', title: '更新失敗', timer: 3000 }));
    }
  };

  const value = {
    wishlist,
    loading,
    groupCount: wishlist?.groups?.length || 0,
    groups: wishlist?.groups || [],
    getWishlist,
    toggleStock,
    isWatched,
    addGroup,
    renameGroup,
    deleteGroup,
    setDefaultGroup,
    addStockToGroup,
    removeStockFromGroup,
    reorderStocks,
    reorderGroups,
  };

  return <WishlistContext.Provider value={value}>{children}</WishlistContext.Provider>;
};

export const useWishlist = () => {
  const context = useContext(WishlistContext);
  if (!context) throw new Error('useWishlist must be used within WishlistProvider');
  return context;
};

import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import {
  Chart,
  BarController,
  BarElement,
  CategoryScale,
  LinearScale,
  Tooltip,
  Legend,
} from 'chart.js';
import dayJS from 'dayjs';
Chart.register(BarController, BarElement, CategoryScale, LinearScale, Tooltip, Legend);

const api_Url = import.meta.env.VITE_API_BASE;

export default function DividendPolicy({ stockId }) {
  const [benifitData, setBenifitData] = useState([]);
  const [priceData, setPriceData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const canvasRef = useRef(null);
  const chartRef = useRef(null);

  // ==============================
  // 抓資料
  // ==============================
  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);

        // 股利資料
        const dividendRes = await axios.get(`${api_Url}/stockbenifit?id=${stockId}`);
        // //console.log('股利資料原始回應', dividendRes.data);

        const dividendRaw = dividendRes.data?.data?.[0]?.data || [];
        // //console.log('股利資料', dividendRaw);

        setBenifitData(Array.isArray(dividendRaw) ? dividendRaw : []);

        // 股價資料
        const priceRes = await axios.get(`${api_Url}/prices?symbolId=${stockId}`);

        let priceArray = [];
        if (Array.isArray(priceRes.data)) {
          priceArray = priceRes.data;
        } else if (Array.isArray(priceRes.data?.data)) {
          priceArray = priceRes.data.data;
        }

        setPriceData(priceArray);
      } catch (err) {
        console.error(err);
        setError('資料載入失敗');
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [stockId]);

  // ==============================
  // 排序股價
  // ==============================
  const sortedPriceData = useMemo(() => {
    if (!Array.isArray(priceData)) return [];
    return [...priceData].sort((a, b) => new Date(a.date) - new Date(b.date));
  }, [priceData]);

  // ==============================
  // 計算填息與股利
  // ==============================
  const dividendSummary = useMemo(() => {
    if (!benifitData.length) return null;

    const validDividend = benifitData.filter((d) => {
      const cash =
        Number(d.CashEarningsDistribution) || Number(d.cashDividend) || Number(d.cash) || 0;
      return cash > 0 && d.CashExDividendTradingDate;
    });
    // //console.log('有效股利資料', validDividend);
    // //console.log('sort', sortedPriceData);

    // ===== 填息計算 =====
    // 證交所在除息日前一日,按該公司當天收盤價減除息值,做為除息日之除息參考價,並據以產生開盤競價基準及計算漲跌停板價格
    let successCount = 0;
    let totalDays = 0;
    const fillValid = validDividend.forEach((div) => {
      const exDate = div.CashExDividendTradingDate;

      const previousDay = [...sortedPriceData]
        .reverse()
        .find((p) => new Date(p.date) < new Date(exDate));
      // //console.log('除息日前一交易日', previousDay);

      if (!previousDay) return;

      const targetPrice = previousDay.close - div.CashEarningsDistribution;
      // //console.log('除息參考價', targetPrice);

      const fillDay = sortedPriceData.find(
        (p) => new Date(p.date) >= new Date(exDate) && Number(p.close) >= Number(targetPrice)
      );
      // //console.log('填息日', fillDay);

      if (fillDay) {
        successCount++;
        const days = (new Date(fillDay.date) - new Date(exDate)) / (1000 * 60 * 60 * 24);
        // //console.log('成功填息', { exDate, fillDate: fillDay.date, days });
        totalDays += days;
      }
    });
    // //console.log('填息計算', { successCount, totalDays, fillValid });

    const fillRate =
      validDividend.length > 0
        ? ((successCount / validDividend.length) * 100).toFixed(2) + '%'
        : '-';

    const avgDays = successCount > 0 ? Math.round(totalDays / successCount) : '-';

    // ===== 年度整理 =====
    const yearly = validDividend.reduce((acc, item) => {
      const rawYear = Number(dayJS(item.date).format('YYYY'));
      // //console.log('rawYear', rawYear);
      const year = rawYear < 1911 ? rawYear + 1911 : rawYear;
      const cash =
        Number(item.CashEarningsDistribution) ||
        Number(item.cashDividend) ||
        Number(item.cash) ||
        0;

      if (!acc[year]) acc[year] = { year, cash: 0 };
      acc[year].cash += cash;
      return acc;
    }, {});

    const yearlyArr = Object.values(yearly).sort((a, b) => a.year - b.year);
    const last10 = yearlyArr.slice(-10);
    const totalDividend = last10.reduce((sum, y) => sum + y.cash, 0);
    // //console.log('年度股利整理', yearlyArr);

    return {
      fillRate,
      avgDays,
      totalDividend,
      yearlyData: yearlyArr,
    };
  }, [benifitData, sortedPriceData]);

  // ==============================
  // Chart Data
  // ==============================
  const barData = useMemo(() => {
    if (!dividendSummary?.yearlyData?.length) {
      return { labels: [], datasets: [] };
    }

    return {
      labels: dividendSummary.yearlyData.map((x) => x.year),
      datasets: [
        {
          label: '現金股利(元)',
          data: dividendSummary.yearlyData.map((x) => x.cash),
          backgroundColor: 'rgba(51,67,255,0.8)',
        },
      ],
    };
  }, [dividendSummary]);

  // ==============================
  // 建立圖表
  // ==============================
  useEffect(() => {
    if (!canvasRef.current) return;
    if (!barData.labels.length) return;

    if (chartRef.current) chartRef.current.destroy();

    const ctx = canvasRef.current.getContext('2d');
    chartRef.current = new Chart(ctx, {
      type: 'bar',
      data: barData,
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: true },
          tooltip: { enabled: true },
        },
        scales: {
          y: { beginAtZero: true },
          x: { title: { display: true, text: '年份' } },
        },
      },
    });

    return () => chartRef.current?.destroy();
  }, [barData]);

  // ==============================
  // UI
  // ==============================
  if (loading) return <div className="text-center py-5">載入中...</div>;
  if (error) return <div className="text-danger text-center py-5">{error}</div>;

  return (
    <div className="container my-4">
      <div className="row g-3 mb-3">
        <div className="col-md-4">
          <div className="card p-3 text-center">
            <div className="text-muted">填息機率</div>
            <div className="fs-3 fw-bold">{dividendSummary?.fillRate}</div>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card p-3 text-center">
            <div className="text-muted">平均填息天數</div>
            <div className="fs-3 fw-bold">{dividendSummary?.avgDays}</div>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card p-3 text-center">
            <div className="text-muted">近10年現金股利總額</div>
            <div className="fs-3 fw-bold">
              ${dividendSummary ? dividendSummary.totalDividend.toFixed(3) : '-'}
            </div>
          </div>
        </div>
      </div>

      <div className="card p-3" style={{ height: 350 }}>
        <div className="text-center mb-2">歷年現金股利</div>
        <canvas ref={canvasRef}></canvas>
      </div>
    </div>
  );
}

import { useEffect, useState } from 'react';
import axios from 'axios';
import { ChevronRight } from 'lucide-react';
import { NavLink, useParams, useNavigate } from 'react-router-dom';

import DividendPolicy from './DividendPolicy';
import StockKLine from './StockKLine';
import StockPriceTrend from './StockPriceTrend';

export default function StockInfo() {
  const { id } = useParams(); // URL 參數 :id
  const navigate = useNavigate();

  const [activeTab, setActiveTab] = useState('股價走勢');
  const [renderTab, setRenderTab] = useState('股價走勢'); // 實際渲染的 tab
  const [mobileDropdownOpen, setMobileDropdownOpen] = useState(false);
  const [stockData, setStockData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  // //console.log('id', id);

  const stockUrl = import.meta.env.VITE_symbolsUrl;
  const tabs = ['股價走勢', '股利政策', '股價 K 線'];

  // 延遲切換 tab,確保圖表完全卸載
  useEffect(() => {
    setRenderTab(''); // 先清空
    const timer = setTimeout(() => {
      setRenderTab(activeTab); // 延遲 50ms 後渲染新 tab
    }, 50);
    return () => clearTimeout(timer);
  }, [activeTab]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        setLoading(true);
        setError(false);

        const res = await axios.get(`${stockUrl}?id=${id}&_embed=prices`);
        const dataArray = res.data.data || res.data;
        // //console.log('dataArray', dataArray);

        if (Array.isArray(dataArray) && dataArray.length > 0) {
          const data = dataArray[0];

          const latest = data.prices?.[data.prices.length - 1] || {};
          const prev = data.prices?.[data.prices.length - 2] || latest;

          const latestPrice = Number(latest.close ?? 0);
          const prevPrice = Number(prev.close ?? latestPrice);
          const change = latestPrice - prevPrice;
          const changePercent = prevPrice ? (change / prevPrice) * 100 : 0;

          setStockData({
            ...data,
            latestPrice,
            change,
            changePercent,
            latestTime: latest.date || '',
            totalVolume: latest.volume ?? 0,
          });
        } else {
          setStockData(null);
          setError(true);
        }
      } catch (err) {
        console.error('載入股票資料失敗:', err);
        setStockData(null);
        setError(true);
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [id, stockUrl]);

  if (loading) {
    return <div style={{ padding: '50px', textAlign: 'center', color: '#666' }}>載入中…</div>;
  }

  if (error || !stockData) {
    return (
      <div style={{ padding: '50px', textAlign: 'center', color: '#666' }}>
        找不到股票 ID: {stockID}
        <br />
        <button onClick={() => navigate('/')} className="btn btn-primary mt-3">
          回首頁
        </button>
      </div>
    );
  }

  return (
    <div className="stock-info-page pt-5">
      {/* 麵包屑 */}
      <div className="custom-container mt-5 text-muted mb-3 d-flex align-items-center gap-1 px-3">
        <NavLink to="/" className="text-muted text-decoration-none">
          首頁
        </NavLink>
        <ChevronRight size={16} />
        <span>
          {stockData.id} {stockData.name}
        </span>
      </div>

      {/* 股票資訊卡 */}
      <div className="custom-container mb-4">
        <div
          className="card rounded-4 shadow-sm"
          style={{
            backgroundColor: '#fff',
            border: 'none',
            padding: '2rem 2.5rem',
          }}
        >
          <div className="d-flex align-items-baseline gap-2 mb-3">
            <div className="fs-5 fw-bold">{stockData.name}</div>
            <div className="text-muted">{stockData.id}</div>
          </div>

          <div className="d-flex align-items-center gap-3 mb-3">
            <div className="fs-2 fw-bold">{stockData.latestPrice.toFixed(2)}</div>

            <div className="d-flex align-items-center gap-2">
              <div
                className="d-flex justify-content-center align-items-center rounded"
                style={{
                  width: '24px',
                  height: '24px',
                  backgroundColor: stockData.change >= 0 ? '#ffe8e8' : '#e8f0ff',
                  color: stockData.change >= 0 ? '#ff4d4f' : '#2962FF',
                  fontSize: '0.9rem',
                  fontWeight: 'bold',
                }}
              >
                {stockData.change >= 0 ? '↑' : '↓'}
              </div>

              <span
                style={{
                  fontSize: '0.9rem',
                  fontWeight: 500,
                  color: stockData.change >= 0 ? '#ff4d4f' : '#2962FF',
                }}
              >
                {(stockData.change ?? 0).toFixed(2)} ({(stockData.changePercent ?? 0).toFixed(2)}%)
              </span>
            </div>
          </div>

          <div className="text-muted" style={{ fontSize: '0.85rem' }}>
            {stockData.latestTime} 更新 | 總量: {(stockData.totalVolume ?? 0).toLocaleString()} 張
          </div>
        </div>
      </div>

      {/* Tab 手機版 */}
      <div className="custom-container mb-4 d-md-none" style={{ position: 'relative' }}>
        <button
          className="stock-dropdown-btn btn-lg w-100"
          onClick={() => setMobileDropdownOpen((p) => !p)}
        >
          {activeTab}
        </button>

        {mobileDropdownOpen && (
          <ul className="dropdown-menu show w-100 mt-2">
            {tabs.map((tab) => (
              <li key={tab}>
                <button
                  className={`dropdown-item ${activeTab === tab ? 'active' : ''}`}
                  onClick={() => {
                    setActiveTab(tab);
                    setMobileDropdownOpen(false);
                  }}
                >
                  {tab}
                </button>
              </li>
            ))}
          </ul>
        )}
      </div>

      {/* Tab 桌機版 */}
      <div className="custom-container d-none d-md-flex mb-4 border-bottom">
        {tabs.map((tab) => (
          <button
            key={tab}
            className={`btn stock-dropdown-btn btn-lg ${activeTab === tab ? 'active' : ''}`}
            onClick={() => setActiveTab(tab)}
          >
            {tab}
          </button>
        ))}
      </div>

      {/* 內容 */}
      <div className="custom-container mb-5">
        {renderTab === '股價走勢' && stockData?.prices?.length > 0 && (
          <StockPriceTrend key={stockData.id + '-line'} stockData={stockData} />
        )}

        {renderTab === '股利政策' && stockData && <DividendPolicy stockId={id} />}

        {renderTab === '股價 K 線' && stockData?.prices?.length > 0 && (
          <StockKLine
            key={stockData.id + '-kline'}
            stockSelect={stockData.id}
            stockUrl={stockUrl}
          />
        )}
      </div>

      <style>{`
        .stock-dropdown-btn.active {
          border-bottom: 3px solid #007bff;
          border-radius: 0;
          color: #007bff;
        }
        .dropdown-item.active {
          font-weight: bold;
          background-color: #e6f0ff;
        }
      `}</style>
    </div>
  );
}

